import{_ as t,o,c as a,ag as r}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"Install the app","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install.md","filePath":"guide/install.md","lastUpdated":1776620726000}'),n={name:"guide/install.md"};function i(s,e,l,h,d,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="install-the-app" tabindex="-1">Install the app <a class="header-anchor" href="#install-the-app" aria-label="Permalink to &quot;Install the app&quot;">​</a></h1><p>Fateh HR comes in two flavours. Pick whichever fits.</p><h2 id="android-apk-recommended" tabindex="-1">Android APK (recommended) <a class="header-anchor" href="#android-apk-recommended" aria-label="Permalink to &quot;Android APK (recommended)&quot;">​</a></h2><p>The native Android app is the best experience — faster, works fully offline, shows native notifications, and supports fingerprint / face unlock.</p><h3 id="step-1-—-download-the-apk" tabindex="-1">Step 1 — Download the APK <a class="header-anchor" href="#step-1-—-download-the-apk" aria-label="Permalink to &quot;Step 1 — Download the APK&quot;">​</a></h3><p>Open this link on your Android phone and tap the latest <code>fatehhr-demo-&lt;version&gt;.apk</code>:</p><p><strong><a href="https://github.com/EnfonoTech/fatehhr/releases/tag/frontend-dev" target="_blank" rel="noreferrer">Latest APK release →</a></strong></p><h3 id="step-2-—-allow-install-from-your-browser" tabindex="-1">Step 2 — Allow install from your browser <a class="header-anchor" href="#step-2-—-allow-install-from-your-browser" aria-label="Permalink to &quot;Step 2 — Allow install from your browser&quot;">​</a></h3><p>Android asks for permission the first time you install from outside the Play Store.</p><ol><li>When you tap the APK, Android says <strong>&quot;For your security, your phone is not allowed to install unknown apps from this source.&quot;</strong></li><li>Tap <strong>Settings</strong> in that popup.</li><li>Turn on <strong>Allow from this source</strong>.</li><li>Go back and tap <strong>Install</strong>.</li></ol><h3 id="step-3-—-open-it" tabindex="-1">Step 3 — Open it <a class="header-anchor" href="#step-3-—-open-it" aria-label="Permalink to &quot;Step 3 — Open it&quot;">​</a></h3><p>After install, tap <strong>Open</strong> (or find &quot;Fateh HR Demo&quot; in your app drawer). You&#39;re ready to log in.</p><div class="tip custom-block"><p class="custom-block-title">Updating later</p><p>When a new version is available your HR team will share the download link again. Tap the new APK → Install → Done. Your login and PIN are preserved across updates.</p></div><h2 id="web-app-any-phone-any-browser" tabindex="-1">Web app (any phone, any browser) <a class="header-anchor" href="#web-app-any-phone-any-browser" aria-label="Permalink to &quot;Web app (any phone, any browser)&quot;">​</a></h2><p>If you can&#39;t install the APK, or you&#39;re on iPhone, you can use the web version.</p><h3 id="step-1-—-open-the-site" tabindex="-1">Step 1 — Open the site <a class="header-anchor" href="#step-1-—-open-the-site" aria-label="Permalink to &quot;Step 1 — Open the site&quot;">​</a></h3><p>Visit: <strong><a href="https://hr-demo.enfonoerp.com/fatehhr" target="_blank" rel="noreferrer">https://hr-demo.enfonoerp.com/fatehhr</a></strong></p><p>(Your company may have its own URL — check with HR.)</p><h3 id="step-2-—-add-to-home-screen" tabindex="-1">Step 2 — Add to home screen <a class="header-anchor" href="#step-2-—-add-to-home-screen" aria-label="Permalink to &quot;Step 2 — Add to home screen&quot;">​</a></h3><p>To make it feel like an app:</p><p><strong>On Chrome / Android:</strong></p><ol><li>Open the site</li><li>Tap the ⋮ menu → <strong>&quot;Install app&quot;</strong> or <strong>&quot;Add to Home screen&quot;</strong></li><li>Confirm — an icon appears on your home screen</li></ol><p><strong>On Safari / iPhone:</strong></p><ol><li>Open the site</li><li>Tap the Share button (box with arrow)</li><li>Scroll down → <strong>&quot;Add to Home Screen&quot;</strong></li><li>Name it &quot;Fateh HR&quot; → <strong>Add</strong></li></ol><p>The web version has almost all features of the app, with these differences:</p><ul><li>Camera/selfie works but requires granting browser permission each session on some devices</li><li>No native biometric unlock (PIN only)</li><li>No background sync when the browser tab is closed</li></ul><h2 id="which-one-should-i-use" tabindex="-1">Which one should I use? <a class="header-anchor" href="#which-one-should-i-use" aria-label="Permalink to &quot;Which one should I use?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Use this</th></tr></thead><tbody><tr><td>Android phone, most of the time</td><td><strong>APK</strong></td></tr><tr><td>iPhone</td><td><strong>Web app</strong> (no APK for iOS yet)</td></tr><tr><td>Shared / demo device</td><td>Web app</td></tr><tr><td>Just testing quickly</td><td>Web app</td></tr></tbody></table><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/login">Log in and set your PIN</a></li><li><a href="/guide/biometric">Enable biometric unlock</a></li></ul>',30)])])}const m=t(n,[["render",i]]);export{c as __pageData,m as default};
